+    for (i, (name, bias)) in rankings.iter().enumerate() {
+        let marker = if *bias > 0.3 {
+            "+"
+        } else if *bias < -0.3 {
+            "-"
+        } else {
+            " "
+        };
+        println!("{}. {} {:23} ({:+.2})", i + 1, marker, name, bias);
+    }
+
+    println!("\n\"Closer to evolution than training.\"");
+}

