+
+        let verdict_str = match &verdict {
+            SafetyVerdict::Allowed { warning, .. } => {
+                if warning.is_some() {
+                    "Allowed (warn)"
+                } else {
+                    "Allowed"
+                }
+            }
+            SafetyVerdict::Blocked { .. } => "BLOCKED",
