+    println!(
+        "Final accumulated stress: {:.3}",
+        organism.accumulated_stress
+    );
+    println!(
+        "Current state: {}",
+        if organism.is_calm() { "Calm" } else { "Active" }
+    );
+
+    println!("\n\"Intelligence as homeostasis, not problem-solving.\"");
+}

