+        }
+        dag
+    }
+
+    #[test]
+    fn test_cache_insert_and_get() {
+        let mut cache = AttentionCache::new(CacheConfig::default());
+        let dag = create_test_dag(3);
+
+        let scores = AttentionScores::new(vec![0.5, 0.3, 0.2]);
+        let expected_scores = scores.scores.clone();
