+
+    #[test]
+    fn test_ucb_selection() {
+        let mechanisms: Vec<Box<dyn DagAttentionMechanism>> = vec![
+            Box::new(MockMechanism {
+                name: "mech1",
+                score_value: 0.5,
+            }),
+            Box::new(MockMechanism {
+                name: "mech2",
+                score_value: 0.7,
+            }),
+            Box::new(MockMechanism {
+                name: "mech3",
