+
+    #[test]
+    fn test_best_mechanism() {
+        let mechanisms: Vec<Box<dyn DagAttentionMechanism>> = vec![
+            Box::new(MockMechanism {
+                name: "poor",
+                score_value: 0.3,
+            }),
+            Box::new(MockMechanism {
+                name: "good",
+                score_value: 0.8,
+            }),
+        ];
+
+        let mut selector = AttentionSelector::new(
