+    }
+
+    #[test]
+    fn test_selector_forward() {
+        let mechanisms: Vec<Box<dyn DagAttentionMechanism>> = vec![Box::new(MockMechanism {
+            name: "test",
+            score_value: 0.5,
+        })];
+
