+        dag.add_edge(root, left1).unwrap();
+        dag.add_edge(left1, left2).unwrap();
+        dag.add_edge(root, right1).unwrap();
+        dag.add_edge(left2, join).unwrap();
+        dag.add_edge(right1, join).unwrap();
