+        assert_eq!(topo_nodes.len(), 5);
+
+        let pos_root = topo_nodes.iter().position(|&x| x == root).unwrap();
+        let pos_join = topo_nodes.iter().position(|&x| x == join).unwrap();
+        assert!(pos_root < pos_join);
+    }
