+) -> f64 {
+    match reward_type {
+        "validation" => {
+            // Pattern validation reward
+            1.0 * stake_weight * pattern_quality
+        }
+        "contribution" => {
+            // Pattern contribution reward
+            10.0 * pattern_quality
+        }
+        "staking" => {
+            // Daily staking reward (5% APY)
+            let daily_rate = (1.05_f64).powf(1.0 / 365.0) - 1.0;
